module.exports = function(RED) {
    "use strict";

    function NeuralFlattenNode(n) {
        RED.nodes.createNode(this, n);
        var node = this;
        node._held = null;

        node.neuralRelease = function() {
            if (node._held) {
                var h = node._held;
                node._held = null;
                h.msg.payload = h.output;
                h.send(h.msg);
                h.done();
            }
        };

        node.on("input", function(msg, send, done) {
            var input = msg.payload;
            if (!Array.isArray(input)) {
                input = [input];
            }

            function flatten(arr) {
                var result = [];
                arr.forEach(function(item) {
                    if (Array.isArray(item)) {
                        result = result.concat(flatten(item));
                    } else if (item != null) {
                        result.push(item);
                    }
                });
                return result;
            }

            var output = flatten(input);

            msg.neural = msg.neural || {};
            msg.neural.type = "flatten";
            msg.neural.shape = [output.length];
            msg.neural.step = (msg.neural.step || 0) + 1;

            if (msg.neural.hold && !node._held) {
                node._held = { output: output, msg: msg, send: send, done: done };
                node.status({ fill: "yellow", shape: "ring", text: "step " + msg.neural.step + " waiting..." });
                return;
            }

            msg.payload = output;
            node.status({ fill: "grey", shape: "dot", text: output.length + " values" });

            if (RED.neural) { RED.neural.outputs[node.id] = { values: output, type: "neural-flatten", name: node.name || "", timestamp: Date.now(), shape: [output.length] }; }

            send(msg);
            done();
        });
    }

    RED.nodes.registerType("neural-flatten", NeuralFlattenNode);
};
